    adaptor.skip(1);

    // Check available data size using buffer_adaptor's size function
    auto available_size = adaptor.size();

    // Calculate expected minimum size (1 byte for data_type + 4 bytes for item_count)
    const size_t min_expected_size = 1 + sizeof(uint32_t);

    // If available size is insufficient, return empty result
    if (available_size < min_expected_size) {
        return DataResult{};
    }

    // Use binary_stream to read item_count and items based on data_type
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);
    uint32_t item_count;
    stream >> item_count;

