    const size_t total_expected_size = min_expected_size + item_size;

    // If available size is insufficient for items, return partial result
    if (available_size < total_expected_size) {
        return result;
    }

    // Read items based on data_type
    if (data_type == 0) {
        // Read integers
        result.int_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            uint32_t value;
            stream >> value;
            result.int_items[i] = value;
        }
    } else if (data_type == 1) {
        // Read floats
        result.float_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            float value;
            stream >> value;
            result.float_items[i] = value;
        }
    }

    return result;
